from langchain_openai import ChatOpenAI
from langchain_core.documents import Document

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)

def summarize_doc(text: str) -> str:
    return llm.invoke(
        f"Summarize this document in 2-3 sentences for a search index:\n{text}"
    ).content.strip()

summary_docs = []
for doc_id, doc in zip(doc_ids, source_docs):
    summary = summarize_doc(doc.page_content)
    summary_docs.append(Document(
        page_content=summary,
        metadata={"doc_id": doc_id, "type": "summary"}
    ))

retriever.vectorstore.add_documents(summary_docs)

# Broad query matches the summary embedding, returns full source doc
results = retriever.invoke("overview of deep learning optimization")
print(results[0].page_content)

def generate_questions(text: str, n: int = 3) -> list[str]:
    prompt = (
        f"Generate {n} distinct questions that this text answers.\n"
        f"Return one question per line, no numbering.\n\nText:\n{text}"
    )
    output = llm.invoke(prompt).content.strip()
    return [q.strip() for q in output.split("\n") if q.strip()]

question_docs = []
for doc_id, doc in zip(doc_ids, source_docs):
    questions = generate_questions(doc.page_content, n=3)
    for q in questions:
        question_docs.append(Document(
            page_content=q,
            metadata={"doc_id": doc_id, "type": "question"}
        ))

retriever.vectorstore.add_documents(question_docs)

# User question closely matches a generated question embedding
results = retriever.invoke("What optimiser is used in modern neural networks?")
print(f"Matched via question index, returning: {results[0].page_content[:80]}...")
